
'use client';

import { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import { MoreHorizontal, Phone, MessageSquare, Edit, FileText, User } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuLabel, DropdownMenuTrigger } from "@/components/ui/dropdown-menu";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { Label } from '@/components/ui/label';
import { Input } from '@/components/ui/input';

const initialChildrenData = [
    { id: 'C001', name: 'Alice Johnson', avatar: 'https://placehold.co/64x64.png', route: 'North Route', school: 'Springfield Elementary', pickupAddress: '123 Maple St', dropoffAddress: '123 Maple St', emergencyContact: 'Carol Johnson | 555-0101' },
    { id: 'C002', name: 'Bob Williams', avatar: 'https://placehold.co/64x64.png', route: 'North Route', school: 'Springfield Elementary', pickupAddress: '456 Oak Ave', dropoffAddress: '456 Oak Ave', emergencyContact: 'David Williams | 555-0102' }
];

type Child = typeof initialChildrenData[0];

export default function ChildManagementPage() {
    const { toast } = useToast();
    const [children, setChildren] = useState(initialChildrenData);
    const [selectedChild, setSelectedChild] = useState<Child | null>(null);
    const [isViewDialogOpen, setIsViewDialogOpen] = useState(false);
    const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);

    const handleContactDriver = (childName: string) => {
        toast({
            title: "Contacting Driver",
            description: `A message has been sent to the driver regarding ${childName}. They will respond when it is safe to do so.`,
        })
    }

    const openViewDialog = (child: Child) => {
        setSelectedChild(child);
        setIsViewDialogOpen(true);
    }
    
    const openEditDialog = (child: Child) => {
        setSelectedChild(child);
        setIsEditDialogOpen(true);
    }

    const handleEditChild = (event: React.FormEvent<HTMLFormElement>) => {
        event.preventDefault();
        if (!selectedChild) return;

        const formData = new FormData(event.currentTarget);
        const updatedChild = {
            name: formData.get('name') as string,
            emergencyContact: formData.get('emergencyContact') as string,
        };
        
        setChildren(children.map(c => c.id === selectedChild.id ? { ...c, ...updatedChild } : c));
        setIsEditDialogOpen(false);
        toast({
            title: "Details Updated",
            description: `Information for ${updatedChild.name} has been updated.`,
        });
    };

  return (
    <div className="space-y-8">
       <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold font-headline">Child Management</h1>
          <p className="text-muted-foreground">View and manage your children's transportation details.</p>
        </div>
      </div>

      <div className="grid gap-6">
        {children.map((child) => (
            <Card key={child.id}>
                <CardHeader className="flex flex-row items-center justify-between">
                    <div className="flex items-center gap-4">
                        <Avatar className="h-16 w-16">
                            <AvatarImage src={child.avatar} alt={child.name} data-ai-hint="child portrait" />
                            <AvatarFallback>{child.name.split(' ').map(n => n[0]).join('')}</AvatarFallback>
                        </Avatar>
                        <div>
                            <CardTitle>{child.name}</CardTitle>
                            <CardDescription>{child.school}</CardDescription>
                        </div>
                    </div>
                     <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                            <Button variant="ghost" size="icon">
                                <MoreHorizontal className="h-5 w-5"/>
                                <span className="sr-only">Actions</span>
                            </Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent align="end">
                            <DropdownMenuLabel>Actions</DropdownMenuLabel>
                            <DropdownMenuItem onSelect={() => openViewDialog(child)}>
                                <FileText className="mr-2 h-4 w-4" /> View Details
                            </DropdownMenuItem>
                            <DropdownMenuItem onSelect={() => openEditDialog(child)}>
                                <Edit className="mr-2 h-4 w-4" /> Edit Details
                            </DropdownMenuItem>
                            <DropdownMenuItem onSelect={() => handleContactDriver(child.name)}>
                                <MessageSquare className="mr-2 h-4 w-4" /> Contact Driver
                            </DropdownMenuItem>
                        </DropdownMenuContent>
                     </DropdownMenu>
                </CardHeader>
                <CardContent>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 text-sm">
                        <div className="space-y-1">
                            <p className="font-medium">Assigned Route</p>
                            <p className="text-muted-foreground">{child.route}</p>
                        </div>
                        <div className="space-y-1">
                            <p className="font-medium">Bus Status</p>
                            <p className="text-muted-foreground">On Time</p>
                        </div>
                         <div className="space-y-1">
                            <p className="font-medium">Pickup Time</p>
                            <p className="text-muted-foreground">Approx. 8:05 AM</p>
                        </div>
                         <div className="space-y-1">
                            <p className="font-medium">Drop-off Time</p>
                            <p className="text-muted-foreground">Approx. 4:30 PM</p>
                        </div>
                    </div>
                </CardContent>
            </Card>
        ))}
      </div>

       {/* View Details Dialog */}
      <Dialog open={isViewDialogOpen} onOpenChange={setIsViewDialogOpen}>
        <DialogContent className="sm:max-w-[425px]">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2"><User className="h-5 w-5 text-primary" /> {selectedChild?.name}'s Details</DialogTitle>
            <DialogDescription>Full details for your child's transportation.</DialogDescription>
          </DialogHeader>
           {selectedChild && (
            <div className="grid gap-4 py-4 text-sm">
                <div className="grid grid-cols-3 items-center gap-4">
                    <Label className="text-right text-muted-foreground">School</Label>
                    <span className="col-span-2">{selectedChild.school}</span>
                </div>
                <div className="grid grid-cols-3 items-center gap-4">
                    <Label className="text-right text-muted-foreground">Route</Label>
                    <span className="col-span-2">{selectedChild.route}</span>
                </div>
                 <div className="grid grid-cols-3 items-center gap-4">
                    <Label className="text-right text-muted-foreground">Pickup Address</Label>
                    <span className="col-span-2">{selectedChild.pickupAddress}</span>
                </div>
                 <div className="grid grid-cols-3 items-center gap-4">
                    <Label className="text-right text-muted-foreground">Drop-off Address</Label>
                    <span className="col-span-2">{selectedChild.dropoffAddress}</span>
                </div>
                <div className="grid grid-cols-3 items-center gap-4">
                    <Label className="text-right text-muted-foreground">Emergency Contact</Label>
                    <span className="col-span-2">{selectedChild.emergencyContact}</span>
                </div>
            </div>
           )}
          <DialogFooter>
            <Button onClick={() => setIsViewDialogOpen(false)}>Close</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
      
      {/* Edit Details Dialog */}
      <Dialog open={isEditDialogOpen} onOpenChange={setIsEditDialogOpen}>
        <DialogContent className="sm:max-w-[425px]">
            <DialogHeader>
                <DialogTitle>Edit Details</DialogTitle>
                <DialogDescription>Update the information for {selectedChild?.name}.</DialogDescription>
            </DialogHeader>
            <form onSubmit={handleEditChild}>
                <div className="grid gap-4 py-4">
                    <div className="grid grid-cols-4 items-center gap-4">
                        <Label htmlFor="name" className="text-right">Name</Label>
                        <Input id="name" name="name" defaultValue={selectedChild?.name} className="col-span-3" />
                    </div>
                     <div className="grid grid-cols-4 items-center gap-4">
                        <Label htmlFor="emergencyContact" className="text-right">Emergency Contact</Label>
                        <Input id="emergencyContact" name="emergencyContact" defaultValue={selectedChild?.emergencyContact} className="col-span-3" />
                    </div>
                </div>
                <DialogFooter>
                    <Button type="submit">Save Changes</Button>
                </DialogFooter>
            </form>
        </DialogContent>
      </Dialog>

    </div>
  );
}
